function autoFormatTime(n){let C=n['value']['replace'](/\D/g,'');switch(C['length']>0x4&&(C=C['slice'](0x0,0x4)),C['length']){case 0x0:case 0x1:case 0x2:n['value']=C;break;case 0x3:if(parseInt(C['slice'](0x0,0x2),0xa)<=0x17)n['value']=C['slice'](0x0,0x2)+':'+C['slice'](0x2);else{let m=C['slice'](0x0,0x1)['padStart'](0x2,'0'),Z=C['slice'](0x1);n['value']=m+':'+Z;}break;case 0x4:let E=C['slice'](0x0,0x2),N=C['slice'](0x2);n['value']=E+':'+N;}}function transformTimeValue(n){let C=n['trim']();if(/^\d{2}$/['test'](C))return C[0x0]['padStart'](0x2,'0')+':'+C[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](C))return 0x3===C['length']?parseInt(C['slice'](0x0,0x2),0xa)<=0x17?C['slice'](0x0,0x2)+':'+C['slice'](0x2):C['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+C['slice'](0x1):C['slice'](0x0,0x2)+':'+C['slice'](0x2);if(C['includes'](':')){let [E,N]=C['split'](':');return N||(N='00'),E=E['padStart'](0x2,'0'),N=N['padStart'](0x2,'0'),E+':'+N;}return C;}